/**
 * Interpolated pseudo-class selector using a runtime variable.
 * \`&:\${highlight}\` expands to \`:active\` and \`:hover\` pseudo style objects,
 * wrapped in \`highlightStyles({ active: ..., hover: ... })\` for runtime selection.
 */
